class Solution:
    def deleteString(self, s):
        n = len(s)
        if n == 0:
            return 0
        lcp = [[0] * (n + 1) for _ in range(n + 1)]
        for i in range(n - 1, -1, -1):
            for j in range(n - 1, -1, -1):
                if s[i] == s[j]:
                    lcp[i][j] = lcp[i + 1][j + 1] + 1
        dp = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            dp[i] = 1
            rem = n - i
            for length in range(1, rem // 2 + 1):
                if lcp[i][i + length] >= length:
                    if 1 + dp[i + length] > dp[i]:
                        dp[i] = 1 + dp[i + length]
        return dp[0]

