var deleteString = function(s) {
    const n = s.length;
    if (n === 0) return 0;
    const lcp = Array.from({ length: n + 1 }, () => new Int32Array(n + 1));
    for (let i = n - 1; i >= 0; i--) {
        for (let j = n - 1; j >= 0; j--) {
            if (s[i] === s[j]) lcp[i][j] = lcp[i + 1][j + 1] + 1;
        }
    }
    const dp = new Int32Array(n + 1);
    for (let i = n - 1; i >= 0; i--) {
        dp[i] = 1;
        const rem = n - i;
        for (let length = 1; length <= Math.floor(rem / 2); length++) {
            if (lcp[i][i + length] >= length) {
                if (1 + dp[i + length] > dp[i]) dp[i] = 1 + dp[i + length];
            }
        }
    }
    return dp[0];
};
